// Command genart authors the ASCII art for the Go port's new plant species and
// writes both the plain .txt and a themed colored .ansi for each growth stage.
// Run from the repo root: `go run ./tools/genart`.
//
// The art bodies below are the source of truth; the .ansi files are generated by
// colorizing each glyph (leaf color by default, an accent color for designated
// runes, and a neutral color for the soil line). Run this whenever the art or
// themes change.
package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

