// pad lays the plant body over a fixed 10-line canvas with the soil at the
// bottom, so every species' soil line lands on the same row.
func pad(body string) []string {
	bodyLines := strings.Split(strings.Trim(body, "\n"), "\n")
	const total = 10
	n := total - len(bodyLines) - 2
	if n < 0 {
		n = 0
	}
	lines := make([]string, n)
	lines = append(lines, bodyLines...)
	lines = append(lines, soil1, soil2)
	return lines
}

func colorize(lines []string, leaf, accent, accentRunes string) string {
	var out strings.Builder
	for i, line := range lines {
		isSoil := i >= len(lines)-2
		for _, r := range line {
			if r == ' ' {
				out.WriteByte(' ')
				continue
			}
			color := leaf
			switch {
			case isSoil:
				color = white
			case strings.ContainsRune(accentRunes, r):
				color = accent
			}
			out.WriteString("\x1b[")
			out.WriteString(color)
			out.WriteByte('m')
			out.WriteRune(r)
		}
		out.WriteByte('\n')
	}
	return out.String()
}

func main() {
	artDir := "art"
	if len(os.Args) > 1 {
		artDir = os.Args[1]
	}
	count := 0
	for _, sp := range allSpecies {
		for i, body := range sp.bodies {
			lines := pad(body)
			stage := fmt.Sprintf("%d", i+1)

			txtPath := filepath.Join(artDir, sp.base+stage+".txt")
			if err := os.WriteFile(txtPath, []byte(strings.Join(lines, "\n")+"\n"), 0o644); err != nil {
				panic(err)
			}

			ansiPath := filepath.Join(artDir, sp.base+stage+".ansi")
			if err := os.WriteFile(ansiPath, []byte(colorize(lines, sp.leaf, sp.accent, sp.accentRunes)), 0o644); err != nil {
				panic(err)
			}
			count += 2
		}
	}
	fmt.Printf("wrote %d art files for %d species to %s\n", count, len(allSpecies), artDir)
}
